from typing import Protocol

class PaymentProvider(Protocol):
    def charge(self, amount_cents: int, currency: str) -> str: ...

class StripeProvider:
    def charge(self, amount_cents: int, currency: str) -> str: ...

class LiqPayProvider:
    def charge(self, amount_cents: int, currency: str) -> str: ...

_REGISTRY: dict[str, type[PaymentProvider]] = {
    "US": StripeProvider,
    "UA": LiqPayProvider,
}

def make_payment_provider(country: str) -> PaymentProvider:
    cls = _REGISTRY.get(country)
    if cls is None:
        raise ValueError(f"No provider for country={country}")
    return cls()

class QueryBuilder {
  private parts: string[] = [];
  private params: unknown[] = [];
  select(cols: string[]): this { this.parts.push(`SELECT ${cols.join(",")}`); return this; }
  from(table: string): this { this.parts.push(`FROM ${table}`); return this; }
  where(clause: string, ...p: unknown[]): this { this.parts.push(`WHERE ${clause}`); this.params.push(...p); return this; }
  build(): { sql: string; params: unknown[] } {
    if (this.parts.length === 0) throw new Error("empty query");
    return Object.freeze({ sql: this.parts.join(" "), params: this.params });
  }
}

from fastapi import Depends, FastAPI

class UserRepo:
    def get(self, id: int): ...

def get_repo() -> UserRepo:
    return UserRepo()

app = FastAPI()

@app.get("/users/{uid}")
def read_user(uid: int, repo: UserRepo = Depends(get_repo)):
    return repo.get(uid)

